#include <vector>

namespace query_employee_hierarchy {

struct Employee {
  sqlgen::PrimaryKey<int> emp_id;
  std::string name;
  std::optional<int> manager_id;
};

struct EmployeeManager {
  std::string employee;
  std::optional<std::string> manager;
};

std::vector<EmployeeManager> query_employee_hierarchy() {
    // Connect to SQLite database
    auto db = sqlgen::sqlite::connect("test_db.sqlite");

    // Define Employee table
    auto employee_table = sqlgen::define_table<Employee>("Employee");

    // Create aliases for self-join (e1 for employee, e2 for manager)
    auto e1 = employee_table.as("e1");
    auto e2 = employee_table.as("e2");

    // Build the LEFT JOIN query
    // SELECT e1.name as employee, e2.name as manager
    // FROM Employee e1
    // LEFT JOIN Employee e2 ON e1.manager_id = e2.emp_id
    auto query = sqlgen::select(
        e1.name.as("employee"),
        e2.name.as("manager")
    )
    .from(e1)
    .left_join(e2).on(e1.manager_id == e2.emp_id);

    // Execute query and fetch results
    auto result = db.execute(query);

    // Transform results into EmployeeManager vector
    std::vector<EmployeeManager> employee_managers;
    for (const auto& row : result) {
        EmployeeManager em;
        em.employee = row.get<std::string>("employee");
        em.manager = row.get<std::optional<std::string>>("manager");
        employee_managers.push_back(em);
    }

    return employee_managers;
}

}  // namespace query_employee_hierarchy

