  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

/**
 * Analyze social network data by creating temporary SQL tables for User and Friendship.
 * Returns: std::vector<FriendConnection>.
 */
std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  // Connect to SQLite database
  auto db = sqlgen::sqlite::Database("test_db.sqlite");

  // Create User table
  db.execute(R"(
    CREATE TABLE IF NOT EXISTS User (
      user_id INTEGER PRIMARY KEY,
      username VARCHAR(50) NOT NULL UNIQUE,
      email VARCHAR(100) NOT NULL UNIQUE,
      join_date DATETIME NOT NULL,
      city VARCHAR(50)
    )
  )");

  // Create Friendship table
  db.execute(R"(
    CREATE TABLE IF NOT EXISTS Friendship (
      user_id1 INTEGER,
      user_id2 INTEGER,
      friendship_date DATETIME NOT NULL,
      PRIMARY KEY (user_id1, user_id2),
      FOREIGN KEY (user_id1) REFERENCES User(user_id),
      FOREIGN KEY (user_id2) REFERENCES User(user_id)
    )
  )");

  // Clear existing data for fresh analysis
  db.execute("DELETE FROM Friendship");
  db.execute("DELETE FROM User");

  // Insert users with default data for required fields
  auto insert_user = db.prepare("INSERT INTO User (user_id, username, email, join_date, city) VALUES (?, ?, ?, ?, ?)");
  for (const auto& user : users) {
    insert_user.bind(
      user.user_id.value,
      user.username,
      user.username + "@example.com",
      "2024-01-01 00:00:00",
      "DefaultCity"
    );
    insert_user.execute();
    insert_user.reset();
  }

  // Insert friendships
  auto insert_friendship = db.prepare("INSERT INTO Friendship (user_id1, user_id2, friendship_date) VALUES (?, ?, ?)");
  for (const auto& friendship : friendships) {
    insert_friendship.bind(
      friendship.user1_id,
      friendship.user2_id,
      friendship.created_at.value
    );
    insert_friendship.execute();
    insert_friendship.reset();
  }

  // Query 1: Use SELF-JOIN to find mutual friends
  auto mutual_friends_result = db.execute(R"(
    SELECT u1.username, u2.username, COUNT(f1.user_id2) as mutual_friends
    FROM User u1
    INNER JOIN Friendship f1 ON u1.user_id = f1.user_id1
    INNER JOIN Friendship f2 ON f1.user_id2 = f2.user_id1
    INNER JOIN User u2 ON f2.user_id2 = u2.user_id
    WHERE u1.user_id < u2.user_id
      AND EXISTS (
        SELECT 1 FROM Friendship f3 
        WHERE f3.user_id1 = u1.user_id AND f3.user_id2 = u2.user_id
      )
    GROUP BY u1.user_id, u2.user_id
    HAVING COUNT(f1.user_id2) > 0
  )");

  // Query 2: Use nested query to find users with more than average friends
  db.execute(R"(
    SELECT u.user_id, u.username, COUNT(f.user_id2) as friend_count
    FROM User u
    LEFT JOIN Friendship f ON u.user_id = f.user_id1
    GROUP BY u.user_id, u.username
    HAVING friend_count > (
      SELECT AVG(friend_count) 
      FROM (SELECT COUNT(*) as friend_count FROM Friendship GROUP BY user_id1)
    )
    ORDER BY friend_count DESC
  )");

  // Query 3: Find friend-of-friend relationships (connected through exactly one mutual friend)
  db.execute(R"(
    SELECT DISTINCT u1.username, u3.username
    FROM User u1
    INNER JOIN Friendship f1 ON u1.user_id = f1.user_id1
    INNER JOIN Friendship f2 ON f1.user_id2 = f2.user_id1
    INNER JOIN User u3 ON f2.user_id2 = u3.user_id
    WHERE u1.user_id != u3.user_id
      AND NOT EXISTS (
        SELECT 1 FROM Friendship f3
        WHERE f3.user_id1 = u1.user_id AND f3.user_id2 = u3.user_id
      )
  )");

  // Query 4: Count friends per user and identify most connected users
  db.execute(R"(
    SELECT u.username, COUNT(f.user_id2) as friend_count
    FROM User u
    LEFT JOIN Friendship f ON u.user_id = f.user_id1
    GROUP BY u.user_id, u.username
    ORDER BY friend_count DESC
    LIMIT 10
  )");

  // Query 5: Find users in same city who are not yet friends (recommendation)
  db.execute(R"(
    SELECT u1.username, u2.username
    FROM User u1
    INNER JOIN User u2 ON u1.city = u2.city AND u1.user_id < u2.user_id
    WHERE u1.city IS NOT NULL
      AND NOT EXISTS (
        SELECT 1 FROM Friendship f
        WHERE f.user_id1 = u1.user_id AND f.user_id2 = u2.user_id
      )
  )");

  // Process results and return friend connections
  std::vector<FriendConnection> results;

  while (mutual_friends_result.next()) {
    FriendConnection conn;
    conn.user1_name = mutual_friends_result.get<std::string>(0);
    conn.user2_name = mutual_friends_result.get<std::string>(1);
    results.push_back(conn);
  }

  return results;
}

}  // namespace analyze_social_network

