# Complete File

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace concat_function {

struct Person {
  sqlgen::PrimaryKey<int> id;
  std::string first_name;
  std::string last_name;
};

struct FullName {
  std::string full_name;
};

/**
 * This function demonstrates CONCAT usage.
 * Returns: query value.
 */
inline auto concat_function() {
    // Define the Person table
    sqlgen::table<Person> person("person");

    // Construct a query to select CONCAT(first_name, ' ', last_name)
    // and map the result to the FullName struct
    return sqlgen::select(
        sqlgen::concat(person.first_name, " ", person.last_name)
            .as(&FullName::full_name)
    ).from(person);
}

}  // namespace concat_function
```

## Explanation:

1. **Define the table**: `sqlgen::table<Person> person("person")` creates a table definition based on the `Person` struct with the table name "person".

2. **Use CONCAT function**: `sqlgen::concat(person.first_name, " ", person.last_name)` creates a SQL CONCAT expression that concatenates the first name, a space, and the last name.

3. **Map to result struct**: `.as(&FullName::full_name)` maps the concatenated result to the `full_name` field of the `FullName` struct.

4. **Build and return query**: `sqlgen::select(...).from(person)` constructs the complete SELECT query and returns it.

The resulting query will be equivalent to:
```sql
SELECT CONCAT(first_name, ' ', last_name) AS full_name FROM person
```

